    <script>
    (function() {
      var section = document.getElementById('bao-chi');
      if (!section) return;

      var track = section.querySelector('.lp-bgi-press-track');
      var items = section.querySelectorAll('.lp-bgi-press-item');
      var viewport = section.querySelector('.lp-bgi-press-track-wrap');
      var dotsWrap = section.querySelector('.lp-bgi-press-dots');
      if (!track || !viewport || !items.length || !dotsWrap) return;

      var currentPage = 0;
      var pageCount = 1;
      var resizeTimer = null;
      var autoTimer = null;
      var pointerDown = false;
      var isDragging = false;
      var startX = 0;
      var startY = 0;
      var deltaX = 0;
      var pointerId = null;
      var dragBaseOffset = 0;

      function getSlidesPerView() {
        var w = window.innerWidth;
        if (w <= 980) return 1.5;
        return 3;
      }

      function getStepWidth() {
        if (items.length < 2) return items[0].getBoundingClientRect().width;
        var first = items[0].getBoundingClientRect();
        var second = items[1].getBoundingClientRect();
        return second.left - first.left;
      }

      function renderDots() {
        var html = '';
        for (var i = 0; i < pageCount; i++) {
          html += '<button type="button" data-page="' + i + '" aria-label="Trang ' + (i + 1) + '"></button>';
        }
        dotsWrap.innerHTML = html;
      }

      function updateDotsState() {
        var dots = dotsWrap.querySelectorAll('button');
        for (var i = 0; i < dots.length; i++) {
          var active = i === currentPage;
          dots[i].classList.toggle('active', active);
          dots[i].setAttribute('aria-current', active ? 'true' : 'false');
        }
      }

      function update(keepPage) {
        var perView = getSlidesPerView();
        var nextPageCount = Math.max(1, Math.ceil(items.length / perView));

        if (!keepPage || currentPage > nextPageCount - 1) currentPage = Math.min(currentPage, nextPageCount - 1);
        if (pageCount !== nextPageCount) {
          pageCount = nextPageCount;
          renderDots();
        }

        var step = getStepWidth();
        var maxOffset = Math.max(0, track.scrollWidth - viewport.clientWidth);
        var targetOffset = Math.min(currentPage * perView * step, maxOffset);
        track.style.transform = 'translate3d(-' + targetOffset + 'px, 0, 0)';

        updateDotsState();
      }

      function goTo(page) {
        currentPage = Math.max(0, Math.min(page, pageCount - 1));
        update(true);
      }

      function getMaxOffset() {
        return Math.max(0, track.scrollWidth - viewport.clientWidth);
      }

      function getCurrentOffset() {
        var perView = getSlidesPerView();
        var step = getStepWidth();
        var maxOffset = getMaxOffset();
        return Math.min(currentPage * perView * step, maxOffset);
      }

      function onGestureStart(clientX, clientY, id) {
        pointerDown = true;
        isDragging = false;
        startX = clientX;
        startY = clientY;
        deltaX = 0;
        pointerId = id;
        dragBaseOffset = getCurrentOffset();
        viewport.classList.add('is-dragging');
        stopAuto();
      }

      function onGestureMove(clientX, clientY) {
        if (!pointerDown) return;
        var moveX = clientX - startX;
        var moveY = clientY - startY;
        if (!isDragging && Math.abs(moveX) > 8 && Math.abs(moveX) > Math.abs(moveY)) {
          isDragging = true;
        }
        if (isDragging) {
          deltaX = moveX;
          var maxOffset = getMaxOffset();
          var nextOffset = dragBaseOffset - deltaX;
          if (nextOffset < 0) nextOffset = nextOffset * 0.25;
          if (nextOffset > maxOffset) nextOffset = maxOffset + (nextOffset - maxOffset) * 0.25;
          track.style.transform = 'translate3d(-' + nextOffset + 'px, 0, 0)';
        }
      }

      function onGestureEnd() {
        if (!pointerDown) return;
        pointerDown = false;
        if (!isDragging) {
          startAuto();
          return;
        }

        var threshold = 28;
        if (deltaX <= -threshold) goTo(currentPage + 1);
        else if (deltaX >= threshold) goTo(currentPage - 1);
        else update(true);

        isDragging = false;
        deltaX = 0;
        pointerId = null;
        viewport.classList.remove('is-dragging');
        startAuto();
      }

      function startAuto() {
        stopAuto();
        if (pageCount <= 1) return;
        autoTimer = window.setInterval(function() {
          var next = currentPage >= pageCount - 1 ? 0 : currentPage + 1;
          goTo(next);
        }, 4500);
      }

      function stopAuto() {
        if (autoTimer) {
          window.clearInterval(autoTimer);
          autoTimer = null;
        }
      }

      dotsWrap.addEventListener('click', function(event) {
        var btn = event.target.closest('button[data-page]');
        if (!btn) return;
        var page = parseInt(btn.getAttribute('data-page'), 10);
        if (!isNaN(page)) goTo(page);
      });

      viewport.addEventListener('dragstart', function(event) {
        event.preventDefault();
      });

      viewport.addEventListener('pointerdown', function(event) {
        if (event.pointerType === 'mouse' && event.button !== 0) return;
        onGestureStart(event.clientX, event.clientY, event.pointerId);
        if (viewport.setPointerCapture) viewport.setPointerCapture(event.pointerId);
      });

      viewport.addEventListener('pointermove', function(event) {
        if (!pointerDown || (pointerId !== null && event.pointerId !== pointerId)) return;
        onGestureMove(event.clientX, event.clientY);
        if (isDragging) event.preventDefault();
      });

      viewport.addEventListener('pointerup', onGestureEnd);
      viewport.addEventListener('pointercancel', onGestureEnd);
      viewport.addEventListener('pointerleave', onGestureEnd);

      section.addEventListener('mouseenter', stopAuto);
      section.addEventListener('mouseleave', startAuto);
      section.addEventListener('focusin', stopAuto);
      section.addEventListener('focusout', startAuto);

      window.addEventListener('resize', function() {
        window.clearTimeout(resizeTimer);
        resizeTimer = window.setTimeout(function() {
          update(true);
          startAuto();
        }, 120);
      });

      update(false);
      startAuto();
    })();
    </script>
  </section>

  <!-- FAQ -->
  <section class="lp-bgi-faq lp-section" id="faq">
    <div class="lp-container">
      <h2>Câu Hỏi Thường Gặp</h2>
      <div class="lp-bgi-faq-list">
        <details class="lp-bgi-faq-item" open="">
          <summary>Giá rẻ 6–9 triệu có đáng tin không?</summary>
          <div class="lp-bgi-faq-answer"><p>Đây thường là giá chỉ tính trụ Implant, chưa bao gồm khớp nối Abutment, mão răng sứ và chi phí ghép xương. Tổng cộng có thể đội lên gấp 2–3 lần. Nha Khoa Đông Nam cam kết báo giá trọn gói ngay từ đầu.</p></div>
        </details>
        <details class="lp-bgi-faq-item">
          <summary>Trồng răng Implant có đau không?</summary>
          <div class="lp-bgi-faq-answer"><p>Không đau trong quá trình thực hiện vì khách hàng đã được gây tê cục bộ hoàn toàn. Sau phẫu thuật có thể hơi sưng nhẹ 5–7 ngày, kiểm soát tốt bằng thuốc theo đơn.</p></div>
        </details>
        <details class="lp-bgi-faq-item">
          <summary>Implant có dùng được vĩnh viễn không?</summary>
          <div class="lp-bgi-faq-answer"><p>Trụ titanium có thể tồn tại 20 năm đến suốt đời nếu chăm sóc đúng cách. Mão sứ bên trên bảo hành 3–20 năm tùy loại. Đây là phương pháp phục hình răng bền nhất hiện có.</p></div>
        </details>
        <details class="lp-bgi-faq-item">
          <summary>Người lớn tuổi có trồng được Implant không?</summary>
          <div class="lp-bgi-faq-answer"><p>Có. Không có giới hạn độ tuổi trồng Implant. Điều kiện quan trọng là sức khỏe toàn thân ổn định và xương hàm đủ điều kiện. Nhiều bệnh nhân trên 70 tuổi vẫn thực hiện thành công.</p></div>
        </details>
        <details class="lp-bgi-faq-item">
          <summary>Trả góp Implant có được không?</summary>
          <div class="lp-bgi-faq-answer"><p>Có. Nha Khoa Đông Nam hỗ trợ chia làm 2 đợt thanh toán giúp khách hàng dễ dàng tiếp cận dịch vụ cấy ghép Implant chất lượng cao mà không gặp áp lực tài chính.</p></div>
        </details>
      </div>
    </div>
